// ✅ NOUVEAU TYPE DE STATUT (Workflow mis à jour)
export type DocumentStatus = 
  | 'imported'
  | 'transcribing'
  | 'transcribed'
  | 'book_project'
  | 'proofreading_1'
  | 'proofreading_2'
  | 'edited';

// ✅ TYPE POUR LE WORKFLOW (5 étapes)
export type WorkflowStep = 1 | 2 | 3 | 4 | 5;

// ✅ NOUVEAUX LABELS DE STATUT
export const STATUS_LABELS: Record<DocumentStatus, string> = {
  imported: '📥 Importé',
  transcribing: '✍️ Transcription en cours',
  transcribed: '✅ Transcrit',
  book_project: '📖 Projet de Livre (PL) en cours',
  proofreading_1: '👁️ Relecture 1 en cours',
  proofreading_2: '👁️👁️ Relecture 2 en cours',
  edited: '🎉 Édité'
};

// ✅ TYPE POUR LE FORMULAIRE
export interface DocumentFormData {
  title: string;
  type: "Transcription" | "Audio" | "Édition" | "Vidéo" | "Image";
  source: string;
  status: DocumentStatus;
  progress: number;
  assigned_to: string;
  tags: string[];
  file_url: string;
  workflow_step?: WorkflowStep;
  content?: string; // ✅ AJOUTÉ pour la transcription
  categories?: {
    id: string;
    name: string;
  };
}

// ✅ TYPE POUR LES DOCUMENTS (avec tous les champs)
export interface Document {
  id: string;
  title: string;
  type: "Transcription" | "Audio" | "Édition" | "Vidéo" | "Image";
  source: string;
  status: DocumentStatus;
  progress: number;
  assigned_to: string;
  tags: string[];
  file_url: string;
  workflow_step: WorkflowStep;
  content?: string;
  categories?: {
    id: string;
    name: string;
  };
  created_at: string;
  updated_at: string;
  created_by?: string;
}
